-- Mettre à jour Export CSV/PDF (ADMIN-05) → promoted
UPDATE ideas SET status = 'promoted', priority = 'haute', category = 'Admin' WHERE title LIKE '%Export%' OR title LIKE '%export%';

-- Mettre à jour Accessibilité RGAA (ACC-01) → promoted
UPDATE ideas SET status = 'promoted', priority = 'haute', category = 'Accessibilité' WHERE title LIKE '%Accessibilit%' OR title LIKE '%RGAA%';

-- Ajouter les entrées journal dans actions_log (colonnes correctes : projectId, actionType, title, author)
INSERT INTO actions_log (projectId, actionType, title, author, result)
SELECT p.id, 'deployment', 'ADMIN-05 : Export CSV/PDF déployé — /mc-api/admin/reports/export?format=csv|pdf', 'Manus', 'success'
FROM projects p LIMIT 1;

INSERT INTO actions_log (projectId, actionType, title, author, result)
SELECT p.id, 'deployment', 'ACC-01 : Audit accessibilité RGAA — 3 écrans enrichis + ACCESSIBILITY_AUDIT.md', 'Manus', 'success'
FROM projects p LIMIT 1;

